/* ============================================================================
   DottoUI core — design tokens, Tailwind theme mapping, and the pixel utility
   language. NO `@import "tailwindcss"` here: this partial is pulled into both the
   landing entry (with preflight) and the Starlight entry (layered, no preflight)
   so the two surfaces share one source of truth. Fonts are loaded via <link>.
   ============================================================================ */

/* Match the landing's `.dark` toggle AND Starlight's `[data-theme="dark"]`. */
@custom-variant dark (&:is(.dark *, [data-theme="dark"] *, .dark, [data-theme="dark"]));

/* ---- shadcn tokens (values sampled from the DottoUI reference) ---------- */
:root {
  --radius: 0rem; /* squared — pixel corners come from .pixel-corner utility */

  --background: oklch(0.9322 0.0103 81.79);          /* #ECE8E1 cream paper */
  --foreground: oklch(0.3076 0.0566 257.95);         /* #1D304C navy ink */

  --card: oklch(0.953 0.0115 84.58);                 /* #F3EFE7 */
  --card-foreground: oklch(0.3076 0.0566 257.95);
  --popover: oklch(0.953 0.0115 84.58);
  --popover-foreground: oklch(0.3076 0.0566 257.95);

  --primary: oklch(0.7115 0.0534 260.39);            /* #8FA3C4 cornflower */
  --primary-foreground: oklch(0.3076 0.0566 257.95);
  --secondary: oklch(0.901 0.0293 82.59);            /* #E8DDC9 warm sand */
  --secondary-foreground: oklch(0.3076 0.0566 257.95);
  --muted: oklch(0.8957 0.0187 86.15);               /* #E2DCCF */
  --muted-foreground: oklch(0.4877 0.0489 262.7);    /* #51607C */
  --accent: oklch(0.7081 0.0796 260.06);             /* #84A2D3 accent / links */
  --accent-foreground: oklch(0.3076 0.0566 257.95);
  --destructive: oklch(0.5616 0.1298 33.73);         /* #B4543F muted brick */
  --destructive-foreground: oklch(0.953 0.0115 84.58);

  --border: oklch(0.3076 0.0566 257.95);             /* hard 2px navy pixel borders */
  --input: oklch(0.3076 0.0566 257.95);
  --ring: oklch(0.7081 0.0796 260.06);

  --chart-1: oklch(0.7081 0.0796 260.06);
  --chart-2: oklch(0.6151 0.0776 265.21);
  --chart-3: oklch(0.8146 0.0273 251.7);
  --chart-4: oklch(0.901 0.0293 82.59);
  --chart-5: oklch(0.4877 0.0489 262.7);

  --sidebar: oklch(0.9322 0.0103 81.79);
  --sidebar-foreground: oklch(0.3076 0.0566 257.95);
  --sidebar-primary: oklch(0.7115 0.0534 260.39);
  --sidebar-primary-foreground: oklch(0.3076 0.0566 257.95);
  --sidebar-accent: oklch(0.901 0.0293 82.59);
  --sidebar-accent-foreground: oklch(0.3076 0.0566 257.95);
  --sidebar-border: oklch(0.3076 0.0566 257.95);
  --sidebar-ring: oklch(0.7081 0.0796 260.06);

  /* pixel system extras */
  --pixel-shadow-color: oklch(0.3076 0.0566 257.95);
  --font-display: "Silkscreen", monospace;
  --font-body: "Space Mono", "Courier New", monospace;
}

:is(.dark, [data-theme="dark"]) {
  --background: oklch(0.2669 0.0484 257.47);         /* #16263D deep navy */
  --foreground: oklch(0.9322 0.0103 81.79);          /* #ECE8E1 cream */

  --card: oklch(0.3172 0.0611 259.79);               /* #1F3251 */
  --card-foreground: oklch(0.9322 0.0103 81.79);
  --popover: oklch(0.3172 0.0611 259.79);
  --popover-foreground: oklch(0.9322 0.0103 81.79);

  --primary: oklch(0.7081 0.0796 260.06);            /* #84A2D3 */
  --primary-foreground: oklch(0.2669 0.0484 257.47);
  --secondary: oklch(0.3509 0.0517 266.03);          /* #2E3A56 */
  --secondary-foreground: oklch(0.9322 0.0103 81.79);
  --muted: oklch(0.3509 0.0517 266.03);
  --muted-foreground: oklch(0.8146 0.0273 251.7);    /* #B6C4D4 */
  --accent: oklch(0.7115 0.0534 260.39);             /* #8FA3C4 */
  --accent-foreground: oklch(0.2669 0.0484 257.47);
  --destructive: oklch(0.6287 0.1217 33.94);         /* #C76B56 */
  --destructive-foreground: oklch(0.2669 0.0484 257.47);

  --border: oklch(0.9322 0.0103 81.79);              /* cream pixel borders */
  --input: oklch(0.9322 0.0103 81.79);
  --ring: oklch(0.7081 0.0796 260.06);

  --sidebar: oklch(0.2669 0.0484 257.47);
  --sidebar-foreground: oklch(0.9322 0.0103 81.79);
  --sidebar-primary: oklch(0.7081 0.0796 260.06);
  --sidebar-primary-foreground: oklch(0.2669 0.0484 257.47);
  --sidebar-accent: oklch(0.3509 0.0517 266.03);
  --sidebar-accent-foreground: oklch(0.9322 0.0103 81.79);
  --sidebar-border: oklch(0.9322 0.0103 81.79);
  --sidebar-ring: oklch(0.7081 0.0796 260.06);

  --pixel-shadow-color: var(--border);               /* cream — shadow reads light-on-dark */
}

/* ---- map tokens into Tailwind's theme so bg-primary / text-foreground work */
@theme inline {
  --color-background: var(--background);
  --color-foreground: var(--foreground);
  --color-card: var(--card);
  --color-card-foreground: var(--card-foreground);
  --color-popover: var(--popover);
  --color-popover-foreground: var(--popover-foreground);
  --color-primary: var(--primary);
  --color-primary-foreground: var(--primary-foreground);
  --color-secondary: var(--secondary);
  --color-secondary-foreground: var(--secondary-foreground);
  --color-muted: var(--muted);
  --color-muted-foreground: var(--muted-foreground);
  --color-accent: var(--accent);
  --color-accent-foreground: var(--accent-foreground);
  --color-destructive: var(--destructive);
  --color-destructive-foreground: var(--destructive-foreground);
  --color-border: var(--border);
  --color-input: var(--input);
  --color-ring: var(--ring);
  --color-chart-1: var(--chart-1);
  --color-chart-2: var(--chart-2);
  --color-chart-3: var(--chart-3);
  --color-chart-4: var(--chart-4);
  --color-chart-5: var(--chart-5);
  --color-sidebar: var(--sidebar);
  --color-sidebar-foreground: var(--sidebar-foreground);
  --color-sidebar-primary: var(--sidebar-primary);
  --color-sidebar-primary-foreground: var(--sidebar-primary-foreground);
  --color-sidebar-accent: var(--sidebar-accent);
  --color-sidebar-accent-foreground: var(--sidebar-accent-foreground);
  --color-sidebar-border: var(--sidebar-border);
  --color-sidebar-ring: var(--sidebar-ring);

  --radius-sm: 0px;
  --radius-md: 0px;
  --radius-lg: 0px;
  --radius-xl: 0px;

  --font-sans: var(--font-body);   /* body/UI = Space Mono */
  --font-mono: var(--font-body);
  --font-display: var(--font-display);
}

/* ---- the "low-pixel" language as Tailwind utilities ---------------------- */

/* Stepped corner — 8px cut with a 4px stair step. Use: class="pixel-corner" */
@utility pixel-corner {
  clip-path: polygon(
    0 8px, 4px 8px, 4px 4px, 8px 4px, 8px 0,
    calc(100% - 8px) 0, calc(100% - 8px) 4px, calc(100% - 4px) 4px, calc(100% - 4px) 8px, 100% 8px,
    100% calc(100% - 8px), calc(100% - 4px) calc(100% - 8px), calc(100% - 4px) calc(100% - 4px), calc(100% - 8px) calc(100% - 4px), calc(100% - 8px) 100%,
    8px 100%, 8px calc(100% - 4px), 4px calc(100% - 4px), 4px calc(100% - 8px), 0 calc(100% - 8px)
  );
}
/* Larger 12px/6px step for big cards & badges */
@utility pixel-corner-lg {
  clip-path: polygon(
    0 12px, 6px 12px, 6px 6px, 12px 6px, 12px 0,
    calc(100% - 12px) 0, calc(100% - 12px) 6px, calc(100% - 6px) 6px, calc(100% - 6px) 12px, 100% 12px,
    100% calc(100% - 12px), calc(100% - 6px) calc(100% - 12px), calc(100% - 6px) calc(100% - 6px), calc(100% - 12px) calc(100% - 6px), calc(100% - 12px) 100%,
    12px 100%, 12px calc(100% - 6px), 6px calc(100% - 6px), 6px calc(100% - 12px), 0 calc(100% - 12px)
  );
}
/* Single-step notch — one 4px chamfer per corner (1-step stair). Use on badges. */
@utility pixel-corner-1 {
  clip-path: polygon(
    0 4px, 4px 0,
    calc(100% - 4px) 0, 100% 4px,
    100% calc(100% - 4px), calc(100% - 4px) 100%,
    4px 100%, 0 calc(100% - 4px)
  );
}
/* Hard offset shadow (drop-shadow so it follows the clipped shape) */
@utility pixel-shadow    { filter: drop-shadow(var(--pf-shadow, 4px) var(--pf-shadow, 4px) 0 var(--pixel-shadow-color)); }
@utility pixel-shadow-sm { filter: drop-shadow(2px 2px 0 var(--pixel-shadow-color)); }
@utility pixel-shadow-none { filter: none; }

/* Pixel BORDER — a crisp 2px frame that follows the notched corners. */
@utility pixel-bordered {
  position: relative;
  isolation: isolate;
  background-color: transparent;
  &::before,
  &::after {
    content: "";
    position: absolute;
    z-index: -1;
    clip-path: polygon(
      0 8px, 4px 8px, 4px 4px, 8px 4px, 8px 0,
      calc(100% - 8px) 0, calc(100% - 8px) 4px, calc(100% - 4px) 4px, calc(100% - 4px) 8px, 100% 8px,
      100% calc(100% - 8px), calc(100% - 4px) calc(100% - 8px), calc(100% - 4px) calc(100% - 4px), calc(100% - 8px) calc(100% - 4px), calc(100% - 8px) 100%,
      8px 100%, 8px calc(100% - 4px), 4px calc(100% - 4px), 4px calc(100% - 8px), 0 calc(100% - 8px)
    );
  }
  &::before { inset: 0; background-color: var(--border); }
  &::after { inset: var(--pf-border, 2px); background-color: var(--pf-fill, var(--card)); }
}

/* Bordered frame with the single-step notch — matches .pixel-corner-1. */
@utility pixel-bordered-1 {
  position: relative;
  isolation: isolate;
  background-color: transparent;
  &::before,
  &::after {
    content: "";
    position: absolute;
    z-index: -1;
    clip-path: polygon(
      0 4px, 4px 0,
      calc(100% - 4px) 0, 100% 4px,
      100% calc(100% - 4px), calc(100% - 4px) 100%,
      4px 100%, 0 calc(100% - 4px)
    );
  }
  &::before { inset: 0; background-color: var(--border); }
  &::after { inset: var(--pf-border, 2px); background-color: var(--pf-fill, var(--card)); }
}

/* Pixel DEPTH — inset bevel for a chiselled 3D-pixel look. */
@utility pixel-depth {
  &::after {
    box-shadow:
      inset 3px 3px 0 0 color-mix(in oklab, white 14%, transparent),
      inset -3px -3px 0 0 color-mix(in oklab, var(--border) 30%, transparent);
  }
}
@utility pixel-depth-fill {
  box-shadow:
    inset 3px 3px 0 0 color-mix(in oklab, white 20%, transparent),
    inset -3px -3px 0 0 color-mix(in oklab, black 22%, transparent);
}
/* Pixelated bitmap rendering for dropped-in pixel art */
@utility pixelated { image-rendering: pixelated; }
/* Headline helper */
@utility font-display { font-family: var(--font-display); }
